// cargar_resso_supabase.mjs
// Carga el RAG del RESSO en la tabla `rags` de Supabase (LIAX Contratistas).
// Mecanismo idéntico al de LIAX educativo: NO usa embeddings; los `chunks`
// son strings y la búsqueda es BM25 en el cliente (searchRags/bm25Score).
//
// Requisitos:  npm i @supabase/supabase-js
// Uso:         SUPABASE_URL=... SUPABASE_SERVICE_KEY=... node cargar_resso_supabase.mjs
//
// ⚠️ Aislamiento: este RAG es del MANDANTE (aplica a todos los contratistas),
//    por eso contratista_id = null y nivel = 'global'. La RLS de la tabla debe
//    permitir LECTURA de filas con contratista_id null a cualquier usuario
//    autenticado, y ESCRITURA solo al rol mandante. El JS oculta; la RLS impide.

import { createClient } from '@supabase/supabase-js';

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY; // service_role para el seed
if (!SUPABASE_URL || !SUPABASE_KEY) {
  console.error('Falta SUPABASE_URL o SUPABASE_SERVICE_KEY'); process.exit(1);
}
const supa = createClient(SUPABASE_URL, SUPABASE_KEY);

